class Solution {
public:
    int minOperations(int n) {
        int count = 0;
        while (n) {
            if (n % 2 == 0) {
                n /= 2;
            } else if (n % 4 == 1 || n == 1) {
                n -= 1;
                count++;
            } else {
                n += 1;
                count++;
            }
        }
        return count;
    }
};
